// 将 { key: { lang: text } } 转换为 { lang: { key: text } }
const locales = {};
for (const [key, translations] of Object.entries(i18nData)) {
  for (const [lang, text] of Object.entries(translations)) {
    if (!locales[lang]) locales[lang] = {};
    locales[lang][key] = text;
  }
}

let currentLang = 'zh';

// 语言代码 → locale key 映射
const LANG_MAP = {
  zh: 'zh', 'zh-cn': 'zh', 'zh-hans': 'zh',
  'zh-tw': 'zh-TW', 'zh-hk': 'zh-TW', 'zh-hant': 'zh-TW',
  en: 'en',
  ko: 'ko',
  de: 'de',
  es: 'es',
  fr: 'fr',
  it: 'it',
  da: 'da',
  ja: 'ja',
  pl: 'pl',
  ru: 'ru',
  ar: 'ar',
  no: 'no', nb: 'no', nn: 'no',
  pt: 'pt-BR', 'pt-br': 'pt-BR',
  th: 'th',
  tr: 'tr',
  uk: 'uk',
};

function resolveLocale(raw) {
  if (!raw) return 'en';
  // 去掉 .UTF-8 等后缀，统一小写
  const cleaned = raw.split('.')[0].replace(/_/g, '-').toLowerCase();
  // 精确匹配
  if (LANG_MAP[cleaned]) return LANG_MAP[cleaned];
  // 取主语言
  const primary = cleaned.split('-')[0];
  if (LANG_MAP[primary]) return LANG_MAP[primary];
  return 'en';
}

export function detectLanguage() {
  const lang = process.env.LANG || process.env.LANGUAGE || process.env.LC_ALL || '';
  return resolveLocale(lang);
}

export function setLang(lang) {
  currentLang = locales[lang] ? lang : 'en';
}

export function getLang() {
  return currentLang;
}

export function t(key, params) {
  let text = locales[currentLang]?.[key] || locales['en'][key] || key;
  if (params) {
    for (const [k, v] of Object.entries(params)) {
      text = text.replaceAll(`{${k}}`, v);
    }
  }
  return text;
}

/**
 * Like t(), but resolves against an explicit locale instead of the process-global
 * currentLang. Used to render the login page in the remote browser's language
 * without mutating shared state. Falls back to en → key.
 */
export function tFor(key, lang, params) {
  let text = locales[lang]?.[key] || locales['en'][key] || key;
  if (params) {
    for (const [k, v] of Object.entries(params)) {
      text = text.replaceAll(`{${k}}`, v);
    }
  }
  return text;
}

/**
 * Pick the best supported locale from an HTTP Accept-Language header
 * (e.g. "en-US,en;q=0.9,zh;q=0.8"). Returns null if the header is empty/unusable
 * so the caller can fall back to the server's configured language.
 */
export function localeFromAcceptLanguage(header) {
  if (!header || typeof header !== 'string') return null;
  const tags = header
    .split(',')
    .map((part) => {
      const [tag, ...params] = part.trim().split(';');
      let q = 1;
      for (const param of params) {
        const m = param.trim().match(/^q=([0-9.]+)$/);
        if (m) q = parseFloat(m[1]);
      }
      return { tag: tag.trim(), q: Number.isFinite(q) ? q : 0 };
    })
    .filter((x) => x.tag && x.tag !== '*')
    .sort((a, b) => b.q - a.q);
  for (const { tag } of tags) {
    const cleaned = tag.replace(/_/g, '-').toLowerCase();
    if (LANG_MAP[cleaned]) return LANG_MAP[cleaned];
    const primary = cleaned.split('-')[0];
    if (LANG_MAP[primary]) return LANG_MAP[primary];
  }
  return null;
}

// 自动检测并设置语言
setLang(detectLanguage());
